public class HashsetDemo {

	public static void main(String[] args) {
		// TODO Auto-generated method stub

		
		HashSet<String> names = new HashSet<String>();
		
		names.add("Tushar");
		names.add("Vedant");
		names.add("Soham");
		names.add("Soham");
		
		System.out.println(names);
	}

}
